function attachSessionObject(req, sessionName, value) {
  Object.defineProperty(req, sessionName, {
    enumerable: true,
    get() {
      return value;
    },
    set(arg) {
      if (arg === null || arg === undefined || arg[REASSIGN]) {
        value = arg;
      } else {
        throw new TypeError('session object cannot be reassigned');
      }
      return undefined;
    },
  });
}

get user() {
  try {
    const {
      config: { identityClaimFilter },
    } = weakRef(this);
    const { idTokenClaims } = this;
    const user = clone(idTokenClaims);
    identityClaimFilter.forEach((claim) => {
      delete user[claim];
    });
    return user;
  } catch {
    return undefined;
  }
}

async fetchUserInfo() {
  const { config } = weakRef(this);

  const { configuration } = await getClient(config);
  const ts = tokenSet.call(this);

  if (!ts || !ts.access_token) {
    throw new Error(
      `Access token is required to fetch user info but none was found in the session.\n`,
    );
  }

  const claims = ts.claims();
  const sub = claims?.sub;
  return oidcClient.fetchUserInfo(configuration, ts.access_token, sub);
}

const cancelSilentLogin = (req, res) => {
  const {
    config: {
      session: {
        cookie: { secure, domain, path, sameSite },
      },
    },
  } = weakRef(req.oidc);
  res.cookie(COOKIE_NAME, true, {
    httpOnly: true,
    secure,
    domain,
    path,
    sameSite,
  });
};

function _validateArgs(uri, options, callback) {
  if (typeof options === 'function' && callback == null) {
    throw new MongooseError('Connection.prototype.openUri() no longer accepts a callback');
  } else if (typeof callback === 'function') {
    throw new MongooseError('Connection.prototype.openUri() no longer accepts a callback');
  }
}

function _getRawCursor(query, queryCursor) {
  try {
    const cursor = query.model.collection.find(query._conditions, queryCursor.options);
    queryCursor.cursor = cursor;
    queryCursor.emit('cursor', cursor);
  } catch (err) {
    queryCursor._markError(err);
    queryCursor.listeners('error').length > 0 && queryCursor.emit('error', queryCursor._error);
  }
}

copy(other) {
  this.messageFormat = other.messageFormat;
  this.stringValue = other.stringValue;
  this.kind = other.kind;
  this.value = other.value;
  this.path = other.path;
  this.reason = other.reason;
  this.message = other.message;
  this.valueType = other.valueType;
}

function shouldFlatten(val) {
  return val &&
      typeof val === 'object' &&
      !(val instanceof Date) &&
      !isBsonType(val, 'ObjectId') &&
      (!Array.isArray(val) || val.length !== 0) &&
      !(val instanceof Buffer) &&
      !isBsonType(val, 'Decimal128') &&
      !(val instanceof Binary);
}

function extractMarkdown(node, sourceText) {
  if (!node.position) {
    return extractText(node); // Fallback to text extraction
  }

  const start = node.position.start.offset;
  const end = node.position.end.offset;

  if (start === undefined || end === undefined) {
    return extractText(node);
  }

  return sourceText.slice(start, end).trim();
}

function isBreakingChange(section, description, version) {
  // Parse version to determine breaking change rules based on semver
  const [major] = version.split('.').map(Number);

  // Version >= 1.0.0: Only Major Changes are breaking
  if (major >= 1) {
    return section === 'Major Changes';
  }

  // Version < 1.0.0: Both Major and Minor Changes are breaking
  return section === 'Major Changes' || section === 'Minor Changes';
}

export function createExtensionPointFactoryMiddleware<T>(options: {
  extensionPoint: ExtensionPoint<T>;
  middleware: (original: T) => Promise<T>;
}): ExtensionPointFactoryMiddleware {
  return OpaqueExtensionPointFactoryMiddleware.createInstance('v1', {
    extensionPointId: options.extensionPoint.id,
    middleware: options.middleware as (original: unknown) => Promise<unknown>,
  });
}

async addKey(options: {
  id: string;
  key: JsonObject & { kid: string };
  expiresAt: Date;
}) {
  await this.client<Row>(TABLE).insert({
    id: options.key.kid,
    key: JSON.stringify(options.key),
    expires_at: options.expiresAt.toISOString(),
  });
}

constructor(
  spec: Spec,
  ignorePaths: RegExp | Function,
  ignoreUndocumented: boolean = false,
  useRequestUrl = false,
) {
  this.apiDoc = spec.apiDoc;
  this.basePaths = spec.basePaths;
  this.routes = spec.routes;
  this.ignorePaths = ignorePaths;
  this.ignoreUndocumented = ignoreUndocumented;
  this.buildRouteMaps(spec.routes);
  this.useRequestUrl = useRequestUrl;
  this.serial = spec.serial;
}

private _schemaGeneral(parameters: ParametersSchema): object {
  // $schema: "http://json-schema.org/draft-04/schema#",
  return {
    paths: this.apiDoc.paths,
    components: this.apiDoc.components,
    required: ['query', 'headers', 'params'],
    properties: { ...parameters, body: {} },
  };
}

function extractErrorsFromResults(results: (SecurityHandlerResult | SecurityHandlerResult[])[]) {
  return results.map(result => {
    if (Array.isArray(result)) {
      return result.map(it => it).filter(it => !it.success);
    }
    return [result].filter(it => !it.success);
  }).flatMap(it => [...it]);
}

public equivalents(): ContentType[] {
  const types: ContentType[] = [];
  if (!this.mediaType) {
    return types;
  }
  types.push(new ContentType(this.mediaType));

  if (!this.parameters['charset']) {
    types.push(new ContentType(`${this.normalize(['charset'])}; charset=utf-8`));
  }
  return types;
}

