const setDraft7Headers = (
	response: Response,
	info: RateLimitInfo,
	windowMs: number,
): void => {
	if (response.headersSent) return

	const windowSeconds = Math.ceil(windowMs / 1000)
	const resetSeconds = getResetSeconds(windowMs, info.resetTime)

	response.setHeader('RateLimit-Policy', `${info.limit};w=${windowSeconds}`)
	response.setHeader(
		'RateLimit',
		`limit=${info.limit}, remaining=${info.remaining}, reset=${resetSeconds}`,
	)
}

ip(ip: string | undefined) {
	if (ip === undefined) {
		throw new ValidationError(
			'ERR_ERL_UNDEFINED_IP_ADDRESS',
			`An undefined 'request.ip' was detected. This might indicate a misconfiguration or the connection being destroyed prematurely.`,
		)
	}

	if (!isIP(ip)) {
		throw new ValidationError(
			'ERR_ERL_INVALID_IP_ADDRESS',
			`An invalid 'request.ip' (${ip}) was detected. Consider passing a custom 'keyGenerator' function to the rate limiter.`,
		)
	}
}

forwardedHeader(request: Request) {
	if (
		request.headers.forwarded &&
		request.ip === request.socket?.remoteAddress
	) {
		// if req.ip is set to something else, assume it's correct and don't warn here
		throw new ValidationError(
			'ERR_ERL_FORWARDED_HEADER',
			`The 'Forwarded' header (standardized X-Forwarded-For) is set but currently being ignored. Add a custom keyGenerator to use a value from this header.`,
		)
	}
}

headersDraftVersion(version?: any) {
	if (
		typeof version !== 'string' ||
		// @ts-expect-error This is fine. If version is not in the array, it will just return false.
		!SUPPORTED_DRAFT_VERSIONS.includes(version)
	) {
		const versionString = SUPPORTED_DRAFT_VERSIONS.join(', ')
		throw new ValidationError(
			'ERR_ERL_HEADERS_UNSUPPORTED_DRAFT_VERSION',
			`standardHeaders: only the following versions of the IETF draft specification are supported: ${versionString}.`,
		)
	}
}

replace(values_to_replace: any, new_value: any) {
  if (!Array.isArray(values_to_replace)) {
    values_to_replace = [values_to_replace];
  }
  return this.customSanitizer(value =>
    values_to_replace.includes(value) ? _.cloneDeep(new_value) : value,
  );
}

isArray(options: { min?: number; max?: number } = {}) {
  return this.custom(
    value =>
      Array.isArray(value) &&
      (typeof options.min === 'undefined' || value.length >= options.min) &&
      (typeof options.max === 'undefined' || value.length <= options.max),
  );
}

const selectFields: SelectFields = (req, fields, locations) =>
  _(fields)
    .flatMap(field =>
      _.flatMap(locations, location => {
        return expandField(req, field, location);
      }),
    )
    // Avoid duplicates if multiple field selections would return the same field twice.
    // E.g. with fields = ['*.foo', 'bar.foo'] and req.body = { bar: { foo: 1 }, baz: { foo: 2 } },
    // the instance bla.foo would appear twice, and baz.foo once.
    .uniqWith(isSameFieldInstance)
    .value();

function createValidityFilter(onlyValidData = true) {
  return !onlyValidData
    ? () => true
    : (field: FieldInstanceBag) => {
        const hasError = field.context.errors.some(
          error =>
            error.type === 'field' &&
            error.location === field.instance.location &&
            error.path === field.instance.path,
        );

        return !hasError;
      };
}

function json (options) {
  const normalizedOptions = normalizeOptions(options, 'application/json')

  const parse = createJsonParser(options)

  const readOptions = {
    ...normalizedOptions,
    // assert charset per RFC 7159 sec 8.1
    isValidCharset: (charset) => charset.slice(0, 4) === 'utf-'
  }

  return function jsonParser (req, res, next) {
    read(req, res, next, parse, debug, readOptions)
  }
}
